export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { width, height } = useVideoConfig();

  const steps = ['STOLEN KEY', 'ACCESS GAINED', 'NO MALWARE', 'SYSTEM COMMAND', 'DEVICE WIPE', 'NO RANSOM', 'TOTAL LOSS'].filter(s => s !== '' && s !== ' ');
  const count = steps.length;
  const stepWidth = 1600 / count;

  return (
    <div style={{
      position: 'absolute',
      top: 0,
      left: 0,
      width: 1920,
      height: 1080,
      overflow: 'hidden',
      backgroundColor: '#F4F2F8',
      fontFamily: 'sans-serif',
    }}>
      <div style={{
        position: 'absolute',
        top: 100,
        left: 160,
        fontSize: 40,
        fontWeight: 'bold',
        color: '#1C1C14',
        letterSpacing: '2px',
        opacity: interpolate(frame, [0, 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
      }}>
        {'SURGICAL ATTACK VECTOR'}
      </div>

      <div style={{
        position: 'absolute',
        top: 400,
        left: 160,
        width: 1600,
        height: 200,
        display: 'flex',
        flexDirection: 'row',
        alignItems: 'center',
      }}>
        {steps.map((step, i) => {
          const startFrame = 30 + (i * 20);
          const opacity = interpolate(frame, [startFrame, startFrame + 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const scale = interpolate(frame, [startFrame, startFrame + 20], [0.8, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

          return (
            <div key={i} style={{
              width: stepWidth,
              height: '100%',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              opacity,
              transform: `scale(${scale})`,
            }}>
              <div style={{
                width: 80,
                height: 80,
                borderRadius: '50%',
                backgroundColor: '#1C1C14',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#FFFFFF',
                fontSize: 32,
                fontWeight: 'bold',
                marginBottom: 24,
              }}>
                {i + 1}
              </div>
              <div style={{
                color: '#1C1C14',
                fontSize: 22,
                fontWeight: '600',
                textAlign: 'center',
                textTransform: 'uppercase',
                letterSpacing: '0.12em',
              }}>
                {step}
              </div>
            </div>
          );
        })}
      </div>

      <div style={{
        position: 'absolute',
        top: 800,
        left: 160,
        width: 1600,
        height: 60,
        backgroundColor: 'rgba(0,0,0,0.05)',
        borderRadius: 8,
        display: 'flex',
        alignItems: 'center',
        padding: '0 40px',
        color: '#7766AA',
        fontSize: 18,
        opacity: interpolate(frame, [200, 230], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' })
      }}>
        {'A wiper attack without a wiper.'}
      </div>
    </div>
  );
};

