  const steps = useMemo(() => [
    { label: 'ECG CAPTURE', desc: '12-lead data recorded' },
    { label: 'TRANSMISSION', desc: 'System failure detected' },
    { label: 'FALLBACK', desc: 'Initiate radio call' },
    { label: 'VERBAL REPORT', desc: 'Describe findings' },
    { label: 'PHYSICIAN REVIEW', desc: 'Manual interpretation' }
  ].filter(s => s.label !== '' && s.label !== ' '), []);

  const count = steps.length;
  const stepWidth = 280;
  const gutter = 40;
  const totalWidth = (count * stepWidth) + ((count - 1) * gutter);
  const startX = (width - totalWidth) / 2;

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#1A1A1A' }}>
      {steps.map((step, i) => {
