        const translateY = interpolate(frame, [startFrame, startFrame + 20], [40, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const connectorWidth = interpolate(frame, [startFrame + 15, startFrame + 40], [0, gutter], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

        return (
          <React.Fragment key={i}>
            <div style={{ position: 'absolute', top: 400, left: startX + (i * (stepWidth + gutter)), width: stepWidth, height: 280, opacity, transform: `translateY(${translateY}px)` }}>
