  const { width, height } = useVideoConfig();

  const nodes = [
    { id: 'SOURCE', x: 200, y: 540, label: 'CORPORATE' },
    { id: 'HOP1', x: 600, y: 300, label: 'FIREWALL' },
    { id: 'HOP2', x: 1000, y: 700, label: 'ISOLATION' },
    { id: 'HOP3', x: 1400, y: 400, label: 'AIR-GAP' },
    { id: 'TARGET', x: 1720, y: 540, label: 'MEDICAL_DEVICES' },
  ];

  const title = 'NETWORK ISOLATION';
  const subtitle = 'AIR-GAPPED HARDWARE';

  const titleOp = interpolate(frame, [0, 30], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#1A1A1A' }}>
      <div style={{ position: 'absolute', top: 60, left: 192, fontSize: 40, fontWeight: 'bold', color: '#0A1A00', opacity: titleOp }}>{title}</div>
