        {nodes.map((node, i) => {
          const reveal = interpolate(frame, [40 + (i * 40), 70 + (i * 40)], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const isTarget = i === nodes.length - 1;
          return (
            <g key={node.id} style={{ opacity: reveal }}>
              {i < nodes.length - 1 && (
                <line 
                  x1={nodes[i].x} y1={nodes[i].y} 
                  x2={nodes[i+1].x} y2={nodes[i+1].y} 
                  stroke={isTarget ? '#AAFF00' : '#00CCEE'} 
                  strokeWidth={4} 
                  strokeDasharray="10 10"
                />
              )}
              <circle 
                cx={node.x} cy={node.y} r={24} 
                fill={isTarget ? '#e63946' : '#2A2A2A'} 
                stroke={isTarget ? '#e63946' : '#AAFF00'} 
                strokeWidth={4} 
              />
              <text 
                x={node.x} y={node.y + 50} 
                fill="#0A1A00" 
                fontSize={16} 
                textAnchor="middle"
              >
                {node.label}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
};

