        {arrowOpacities.map((op, i) => {
          const x = startX + (i + 1) * boxW + i * arrowW
          const cy = boxY + boxH / 2
          return (
            <g key={i} style={{ opacity: op }}>
              <line
                x1={x}
                y1={cy}
                x2={x + arrowW - 10}
                y2={cy}
                stroke="#888888"
                strokeWidth={2}
              />
              <polygon
                points={`${x + arrowW - 10},${cy - 8} ${x + arrowW},${cy} ${x + arrowW - 10},${cy + 8}`}
                fill="#888888"
              />
            </g>
          )
        })}
      </svg>
    </div>
  )
}

